CREATE OR REPLACE FUNCTION __mj."spCreateAIAgentSearchScope"(
    IN p_ID UUID DEFAULT NULL,
    IN p_AgentID UUID DEFAULT NULL,
    IN p_SearchScopeID UUID DEFAULT NULL,
    IN p_Phase VARCHAR(20) DEFAULT NULL,
    IN p_Status VARCHAR(20) DEFAULT NULL,
    IN p_StartAt TIMESTAMPTZ DEFAULT NULL,
    IN p_EndAt TIMESTAMPTZ DEFAULT NULL,
    IN p_Priority INTEGER DEFAULT NULL,
    IN p_MaxResults INTEGER DEFAULT NULL,
    IN p_MinScore NUMERIC(5,4) DEFAULT NULL,
    IN p_QueryTemplateID UUID DEFAULT NULL,
    IN p_FusionWeightsOverride TEXT DEFAULT NULL,
    IN p_IsDefault BOOLEAN DEFAULT NULL
)
RETURNS SETOF __mj."vwAIAgentSearchScopes" AS
$$
BEGIN
IF p_ID IS NOT NULL THEN
        -- User provided a value, use it
        INSERT INTO __mj."AIAgentSearchScope"
            (
                "ID",
                "AgentID",
                "SearchScopeID",
                "Phase",
                "Status",
                "StartAt",
                "EndAt",
                "Priority",
                "MaxResults",
                "MinScore",
                "QueryTemplateID",
                "FusionWeightsOverride",
                "IsDefault"
            )
        VALUES
            (
                p_ID,
                p_AgentID,
                p_SearchScopeID,
                COALESCE(p_Phase, 'Both'),
                COALESCE(p_Status, 'Active'),
                p_StartAt,
                p_EndAt,
                COALESCE(p_Priority, 100),
                p_MaxResults,
                p_MinScore,
                p_QueryTemplateID,
                p_FusionWeightsOverride,
                COALESCE(p_IsDefault, FALSE)
            );
    ELSE
        -- No value provided, let database use its default (e.g., gen_random_uuid())
        INSERT INTO __mj."AIAgentSearchScope"
            (
                "AgentID",
                "SearchScopeID",
                "Phase",
                "Status",
                "StartAt",
                "EndAt",
                "Priority",
                "MaxResults",
                "MinScore",
                "QueryTemplateID",
                "FusionWeightsOverride",
                "IsDefault"
            )
        VALUES
            (
                p_AgentID,
                p_SearchScopeID,
                COALESCE(p_Phase, 'Both'),
                COALESCE(p_Status, 'Active'),
                p_StartAt,
                p_EndAt,
                COALESCE(p_Priority, 100),
                p_MaxResults,
                p_MinScore,
                p_QueryTemplateID,
                p_FusionWeightsOverride,
                COALESCE(p_IsDefault, FALSE)
            );
    END IF;
    -- return the new record from the base view, which might have some calculated fields
    RETURN QUERY SELECT * FROM __mj."vwAIAgentSearchScopes" WHERE "ID" = p_ID;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION __mj."spUpdateAIAgentSearchScope"(
    IN p_ID UUID,
    IN p_AgentID UUID,
    IN p_SearchScopeID UUID,
    IN p_Phase VARCHAR(20),
    IN p_Status VARCHAR(20),
    IN p_StartAt TIMESTAMPTZ,
    IN p_EndAt TIMESTAMPTZ,
    IN p_Priority INTEGER,
    IN p_MaxResults INTEGER,
    IN p_MinScore NUMERIC(5,4),
    IN p_QueryTemplateID UUID,
    IN p_FusionWeightsOverride TEXT,
    IN p_IsDefault BOOLEAN
)
RETURNS SETOF __mj."vwAIAgentSearchScopes" AS
$$
DECLARE
    _v_row_count INTEGER;
BEGIN
UPDATE
        __mj."AIAgentSearchScope"
    SET
        "AgentID" = p_AgentID,
        "SearchScopeID" = p_SearchScopeID,
        "Phase" = p_Phase,
        "Status" = p_Status,
        "StartAt" = p_StartAt,
        "EndAt" = p_EndAt,
        "Priority" = p_Priority,
        "MaxResults" = p_MaxResults,
        "MinScore" = p_MinScore,
        "QueryTemplateID" = p_QueryTemplateID,
        "FusionWeightsOverride" = p_FusionWeightsOverride,
        "IsDefault" = p_IsDefault
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT * FROM __mj."vwAIAgentSearchScopes" WHERE 1=0;
    ELSE
        RETURN QUERY SELECT * FROM __mj."vwAIAgentSearchScopes" WHERE "ID" = p_ID;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION __mj."spDeleteAIAgentSearchScope"(
    IN p_ID UUID
)
RETURNS TABLE("_result_id" UUID) AS
$$
DECLARE
    _v_row_count INTEGER;
BEGIN
DELETE FROM
        __mj."AIAgentSearchScope"
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT NULL::UUID AS "_result_id";
    ELSE
        RETURN QUERY SELECT p_ID::UUID AS "_result_id";
    END IF;
END;
$$ LANGUAGE plpgsql;

