                "IsGlobal",
                "IsDefault",
                "OwnerUserID",
                "Status",
                "StartAt",
                "EndAt",
                "ScopeConfig",
                "SearchContextConfig",
                "RerankerBudgetCents"
            )
        VALUES
            (
                p_Name,
                p_Description,
                p_Icon,
                COALESCE(p_IsGlobal, FALSE),
                COALESCE(p_IsDefault, FALSE),
                p_OwnerUserID,
                COALESCE(p_Status, 'Active'),
