                "Status",
                "FailureReason",
                "ProvidersJSON"
            )
        VALUES
            (
                p_SearchScopeID,
                p_UserID,
                p_AIAgentID,
                p_Query,
                p_TotalDurationMs,
                COALESCE(p_ResultCount, 0),
                p_RerankerName,
                p_RerankerCostCents,
                p_Status,
                p_FailureReason,
                p_ProvidersJSON
            );
    END IF;
    -- return the new record from the base view, which might have some calculated fields
    RETURN QUERY SELECT * FROM __mj."vwSearchExecutionLogs" WHERE "ID" = p_ID;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION __mj."spUpdateSearchExecutionLog"(
    IN p_ID UUID,
    IN p_SearchScopeID UUID,
    IN p_UserID UUID,
    IN p_AIAgentID UUID,
    IN p_Query TEXT,
    IN p_TotalDurationMs INTEGER,
    IN p_ResultCount INTEGER,
    IN p_RerankerName VARCHAR(100),
    IN p_RerankerCostCents NUMERIC(10,4),
    IN p_Status VARCHAR(20),
    IN p_FailureReason VARCHAR(500),
    IN p_ProvidersJSON TEXT
)
RETURNS SETOF __mj."vwSearchExecutionLogs" AS
$$
DECLARE
    _v_row_count INTEGER;
BEGIN
UPDATE
        __mj."SearchExecutionLog"
    SET
        "SearchScopeID" = p_SearchScopeID,
        "UserID" = p_UserID,
        "AIAgentID" = p_AIAgentID,
        "Query" = p_Query,
        "TotalDurationMs" = p_TotalDurationMs,
        "ResultCount" = p_ResultCount,
        "RerankerName" = p_RerankerName,
        "RerankerCostCents" = p_RerankerCostCents,
        "Status" = p_Status,
        "FailureReason" = p_FailureReason,
        "ProvidersJSON" = p_ProvidersJSON
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT * FROM __mj."vwSearchExecutionLogs" WHERE 1=0;
    ELSE
        RETURN QUERY SELECT * FROM __mj."vwSearchExecutionLogs" WHERE "ID" = p_ID;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION __mj."spDeleteSearchExecutionLog"(
    IN p_ID UUID
)
RETURNS TABLE("_result_id" UUID) AS
$$
DECLARE
    _v_row_count INTEGER;
BEGIN
DELETE FROM
        __mj."SearchExecutionLog"
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT NULL::UUID AS "_result_id";
    ELSE
        RETURN QUERY SELECT p_ID::UUID AS "_result_id";
    END IF;
END;
$$ LANGUAGE plpgsql;

