        p_MJTasks_AgentID_CompletedAt := _rec."CompletedAt";
        -- Set the FK field to NULL
        p_MJTasks_AgentID_AgentID := NULL;
        -- Call the update SP for the related entity
        PERFORM __mj."spUpdateTask"(p_MJTasks_AgentIDID, p_MJTasks_AgentID_ParentID, p_MJTasks_AgentID_Name, p_MJTasks_AgentID_Description, p_MJTasks_AgentID_TypeID, p_MJTasks_AgentID_EnvironmentID, p_MJTasks_AgentID_ProjectID, p_MJTasks_AgentID_ConversationDetailID, p_MJTasks_AgentID_UserID, p_MJTasks_AgentID_AgentID, p_MJTasks_AgentID_Status, p_MJTasks_AgentID_PercentComplete, p_MJTasks_AgentID_DueAt, p_MJTasks_AgentID_StartedAt, p_MJTasks_AgentID_CompletedAt);

    END LOOP;

    

    DELETE FROM
        __mj."AIAgent"
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT NULL::UUID AS "_result_id";
    ELSE
        RETURN QUERY SELECT p_ID::UUID AS "_result_id";
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION __mj."spCreateSearchScopeTestQuery"(
    IN p_ID UUID DEFAULT NULL,
    IN p_SearchScopeID UUID DEFAULT NULL,
    IN p_Label VARCHAR(200) DEFAULT NULL,
    IN p_Query TEXT DEFAULT NULL,
    IN p_ExpectedTopResultEntity VARCHAR(255) DEFAULT NULL,
    IN p_ExpectedTopResultRecordID UUID DEFAULT NULL,
    IN p_Notes TEXT DEFAULT NULL
)
RETURNS SETOF __mj."vwSearchScopeTestQueries" AS
$$
BEGIN
IF p_ID IS NOT NULL THEN
        -- User provided a value, use it
        INSERT INTO __mj."SearchScopeTestQuery"
            (
                "ID",
                "SearchScopeID",
                "Label",
                "Query",
                "ExpectedTopResultEntity",
                "ExpectedTopResultRecordID",
                "Notes"
            )
        VALUES
            (
                p_ID,
                p_SearchScopeID,
                p_Label,
                p_Query,
                p_ExpectedTopResultEntity,
                p_ExpectedTopResultRecordID,
                p_Notes
            );
    ELSE
        -- No value provided, let database use its default (e.g., gen_random_uuid())
        INSERT INTO __mj."SearchScopeTestQuery"
            (
                "SearchScopeID",
                "Label",
                "Query",
                "ExpectedTopResultEntity",
                "ExpectedTopResultRecordID",
                "Notes"
            )
        VALUES
            (
                p_SearchScopeID,
                p_Label,
                p_Query,
                p_ExpectedTopResultEntity,
                p_ExpectedTopResultRecordID,
                p_Notes
            );
    END IF;
    -- return the new record from the base view, which might have some calculated fields
    RETURN QUERY SELECT * FROM __mj."vwSearchScopeTestQueries" WHERE "ID" = p_ID;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION __mj."spUpdateSearchScopeTestQuery"(
    IN p_ID UUID,
    IN p_SearchScopeID UUID,
    IN p_Label VARCHAR(200),
    IN p_Query TEXT,
    IN p_ExpectedTopResultEntity VARCHAR(255),
    IN p_ExpectedTopResultRecordID UUID,
    IN p_Notes TEXT
)
RETURNS SETOF __mj."vwSearchScopeTestQueries" AS
$$
DECLARE
    _v_row_count INTEGER;
BEGIN
UPDATE
        __mj."SearchScopeTestQuery"
    SET
        "SearchScopeID" = p_SearchScopeID,
        "Label" = p_Label,
        "Query" = p_Query,
        "ExpectedTopResultEntity" = p_ExpectedTopResultEntity,
        "ExpectedTopResultRecordID" = p_ExpectedTopResultRecordID,
        "Notes" = p_Notes
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT * FROM __mj."vwSearchScopeTestQueries" WHERE 1=0;
    ELSE
        RETURN QUERY SELECT * FROM __mj."vwSearchScopeTestQueries" WHERE "ID" = p_ID;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION __mj."spDeleteSearchScopeTestQuery"(
    IN p_ID UUID
)
RETURNS TABLE("_result_id" UUID) AS
$$
DECLARE
    _v_row_count INTEGER;
BEGIN
DELETE FROM
        __mj."SearchScopeTestQuery"
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT NULL::UUID AS "_result_id";
    ELSE
        RETURN QUERY SELECT p_ID::UUID AS "_result_id";
    END IF;
END;
$$ LANGUAGE plpgsql;


